#include <bits/stdc++.h>
using namespace std;
int n,m,a[100005],f[100005][20];
int main(){
	memset(f,127,sizeof(f));
	cin>>n>>m;
	for(int i=1;i<=n;i++)cin>>a[i];
	for(int i=n;i;i--){
		for(int j=0;i+pow(2,j)-1<=n;j++)f[i][j]=(j==0? a[i]:min(f[i][j-1],f[i+int(pow(2,j-1))][j-1]));
	}
	/*for(int i=1;i<=n;i++){
		for(int j=0;i+pow(2,j)-1<=n;j++)cout<<f[i][j]<<' ';
		cout<<endl;
	}*/
	while(m--){
	    int l,r,k;
	    cin>>l>>r;
	    k=log2(r-l+1);
	    cout<<min(f[l][k],f[r-int(pow(2,k))+1][k])<<' ';
	}
	return 0;
}
